from api.client.http_client import HttpClientclass IdmProviderMethod(HttpClient):    """    Методы группы 'Авторизация' из https://im-docs.corp.mail.ru/    """    def idm_provider_create(self, url, token: str) -> dict:        """        Добавить тип аутентификации пользователю        Добавление нового провайдера аутентификации пользователю        :param token: Токен действия        :return: тело ответа сервера        """        return self.post(url + "/api/v133/idm/provider/create", headers={"Authorization": self.token}, data={"token": token})    def idm_provider_delete(self, url, token: str) -> dict:        """        Удаление типа аутентификации из аккаунта пользователя        :param token: Токен действия        :return: тело ответа сервера        """        return self.post(url + "/api/v133/idm/provider/delete", headers={"Authorization": self.token}, data={"token": token})    def idm_provider_status(self, url, token: str) -> dict:        """        Получение списка статусов возможных аутентификаций для пользователя        :param token: Токен действия        :return: тело ответа сервера        """        return self.post(url + "/api/v133/idm/provider/status", headers={"Authorization": self.token}, data={"token": token})    def idm_provider_list(self, url, email: str) -> dict:        """        Email пользователя по которому определяется доступный список видов аутентификации        :param email: Токен действия        :return: тело ответа сервера        """        return self.post(            url + "/api/v133/idm/provider/list",            json={                "email": email,            },        )